(function(){if(window.self!==window.top){return;}
if(window.__customContextMenuInitialized){return;}
window.__customContextMenuInitialized=true;let menu=null;let currentLink=null;let currentSelectedText='';let tabsBarOverlay=null;function getTabsBar(){return document.querySelector('.md-tabs');}
function getHeaderBar(){return document.querySelector('.md-header');}
function hasTabsBarOverlay(){return Boolean(tabsBarOverlay&&document.body.contains(tabsBarOverlay));}
function createMenu(){const element=document.createElement('div');element.className='site-context-menu';element.setAttribute('role','menu');element.setAttribute('aria-hidden','true');element.innerHTML='<div class="site-context-menu__panel"></div>';element.addEventListener('click',function(event){const actionItem=event.target.closest('[data-action]');if(!actionItem)return;event.preventDefault();event.stopPropagation();const action=actionItem.getAttribute('data-action');handleAction(action);});document.body.appendChild(element);return element;}
function ensureMenu(){if(!menu){menu=createMenu();}
return menu;}
function getSelectedText(target){const selection=window.getSelection?window.getSelection():null;const pageSelection=selection?selection.toString().trim():'';if(pageSelection){return pageSelection;}
const input=target.closest('textarea, input[type="text"], input[type="search"], input[type="url"], input[type="tel"], input[type="email"], input[type="password"]');if(!input||typeof input.selectionStart!=='number'||typeof input.selectionEnd!=='number'){return'';}
if(input.selectionStart===input.selectionEnd){return'';}
return input.value.slice(input.selectionStart,input.selectionEnd).trim();}
function getPreviewableLink(target){const link=target.closest('a[href]');if(!link){return null;}
const href=link.getAttribute('href');if(!href){return null;}
if(href.startsWith('#')||href.startsWith('javascript:')||href.startsWith('mailto:')||href.startsWith('tel:')){return null;}
return link;}
function isInCommentArea(target){return Boolean(target.closest('#waline'));}
function isTabsBarHidden(){const tabsBar=getTabsBar();if(!tabsBar){return false;}
if(hasTabsBarOverlay()){return false;}
const style=window.getComputedStyle(tabsBar);if(style.display==='none'||style.visibility==='hidden'||Number(style.opacity)===0){return true;}
const rect=tabsBar.getBoundingClientRect();if(rect.width===0||rect.height===0){return true;}
const headerBar=getHeaderBar();const headerBottom=headerBar?headerBar.getBoundingClientRect().bottom:0;const isVisibleBelowHeader=rect.bottom>headerBottom+4&&rect.top<window.innerHeight;return!isVisibleBelowHeader;}
function resetTabsBarReveal(){if(!hasTabsBarOverlay()){return;}
tabsBarOverlay.remove();tabsBarOverlay=null;}
function clearTabsBarCloneState(tabsBarClone){tabsBarClone.removeAttribute('hidden');tabsBarClone.removeAttribute('data-md-state');tabsBarClone.style.cssText='';const clonedNodes=tabsBarClone.querySelectorAll('[hidden], [data-md-state]');clonedNodes.forEach(function(node){node.removeAttribute('hidden');node.removeAttribute('data-md-state');});const tabsList=tabsBarClone.querySelector('.md-tabs__list');if(tabsList){tabsList.classList.remove('show-hover-overlay','animating-left','animating-right');}}
function revealTabsBar(){const tabsBar=getTabsBar();if(!tabsBar){return;}
const headerBar=getHeaderBar();const headerBottom=headerBar?headerBar.getBoundingClientRect().bottom:0;const tabsClone=tabsBar.cloneNode(true);resetTabsBarReveal();clearTabsBarCloneState(tabsClone);tabsClone.classList.add('site-tabs-manual-overlay');tabsClone.setAttribute('aria-hidden','false');tabsClone.style.position='fixed';tabsClone.style.top=headerBottom+'px';tabsClone.style.left='0';tabsClone.style.right='0';tabsClone.style.zIndex='9996';tabsClone.style.pointerEvents='auto';document.body.appendChild(tabsClone);tabsBarOverlay=tabsClone;}
function buildMenuItems(){const items=[];if(currentSelectedText){items.push({action:'copy',label:'复制选中的内容'});}
if(currentLink&&typeof window.openLinkPreview==='function'){items.push({action:'preview',label:'在预览窗口打开'});}
if(isTabsBarHidden()){items.push({action:'show-tabs',label:'临时显示导航栏的内容'});}
items.push({action:'print',label:'输出为 PDF'});return items;}
function renderMenu(items){const menuElement=ensureMenu();const panel=menuElement.querySelector('.site-context-menu__panel');panel.innerHTML=items.map(function(item){return'<button class="site-context-menu__item" type="button" role="menuitem" data-action="'+item.action+'">'+
'<span class="site-context-menu__label">'+item.label+'</span>'+
'</button>';}).join('');}
function positionMenu(x,y){const menuElement=ensureMenu();const panel=menuElement.querySelector('.site-context-menu__panel');const verticalOffset=10;menuElement.classList.add('is-open');menuElement.setAttribute('aria-hidden','false');menuElement.style.left='0';menuElement.style.top='0';const rect=panel.getBoundingClientRect();const padding=12;const maxLeft=Math.max(padding,window.innerWidth-rect.width-padding);const maxTop=Math.max(padding,window.innerHeight-rect.height-padding);const left=Math.min(x,maxLeft);const top=Math.min(y+verticalOffset,maxTop);menuElement.style.left=left+'px';menuElement.style.top=top+'px';}
function hideMenu(){if(!menu){return;}
menu.classList.remove('is-open');menu.setAttribute('aria-hidden','true');currentLink=null;currentSelectedText='';}
async function copyText(text){if(!text){return;}
if(navigator.clipboard&&typeof navigator.clipboard.writeText==='function'){await navigator.clipboard.writeText(text);return;}
const textarea=document.createElement('textarea');textarea.value=text;textarea.setAttribute('readonly','readonly');textarea.style.position='fixed';textarea.style.top='-9999px';textarea.style.left='-9999px';document.body.appendChild(textarea);textarea.select();document.execCommand('copy');document.body.removeChild(textarea);}
function handleAction(action){const selectedText=currentSelectedText;const link=currentLink;hideMenu();if(action==='copy'){copyText(selectedText).catch(function(){});return;}
if(action==='preview'){if(link&&typeof window.openLinkPreview==='function'){window.openLinkPreview(link);}
return;}
if(action==='show-tabs'){revealTabsBar();return;}
if(action==='print'){window.print();}}
document.addEventListener('contextmenu',function(event){const target=event.target;if(!(target instanceof Element)){return;}
if(isInCommentArea(target)){hideMenu();return;}
if(menu&&menu.contains(target)){event.preventDefault();return;}
currentSelectedText=getSelectedText(target);currentLink=getPreviewableLink(target);renderMenu(buildMenuItems());positionMenu(event.clientX,event.clientY);event.preventDefault();event.stopPropagation();},true);document.addEventListener('click',function(event){if(!menu||!menu.classList.contains('is-open')){if(event.target instanceof Element){if(hasTabsBarOverlay()&&!tabsBarOverlay.contains(event.target)){resetTabsBarReveal();}}
return;}
if(menu.contains(event.target)){return;}
hideMenu();},true);document.addEventListener('keydown',function(event){if(event.key==='Escape'){hideMenu();resetTabsBarReveal();}});window.addEventListener('resize',function(){hideMenu();resetTabsBarReveal();});window.addEventListener('blur',function(){hideMenu();resetTabsBarReveal();});document.addEventListener('scroll',function(){hideMenu();resetTabsBarReveal();},true);})();